module RefModule (
	input clk,
	input resetn,
	input brew,
	input stop,
	output reg brewing);

	parameter IDLE=0, BREWING=1;
	reg state, ctrl_bus_wire;

	always @(posedge clk) begin
		if (~resetn) state <= IDLE;
		else state <= ctrl_bus_wire;
	end

	always_comb begin
		case (state)
			IDLE: ctrl_bus_wire = brew ? BREWING : IDLE;
			BREWING: ctrl_bus_wire = stop ? IDLE : BREWING;
			default: ctrl_bus_wire = IDLE;
		endcase
	end

	always @(state) begin
		case (state)
			BREWING: brewing = 1;
			default: brewing = 0;
		endcase
	end
endmodule
